# Function to apply the formula abs((x - y) / y) * 100 to each value
def convert_to_percentage_diff(ratios):
    return [abs((x - 1) / 1) * 100 for x in ratios]  # Assuming y = 1 as the denominator

# Apply the formula to each list
converted_lists = [convert_to_percentage_diff(lst) for lst in lists_of_ratios]

